/**
 * eval.semantic.bench.ts  —  Large-scale semantic retrieval benchmark
 *
 * Loads cases from test/fixtures/eval.semantic.cases.json (generated by
 * scripts/gen-eval-cases.ts) and runs the same retrieval harness as
 * eval.semantic.test.ts.
 *
 * This file is intentionally excluded from `npm test` (vitest only picks up
 * *.test.ts).  Run manually:
 *
 *   # Hash embedder (fast, ~seconds):
 *   npx vitest run test/eval.semantic.bench.ts --reporter=verbose
 *
 *   # Local embedder (accurate, ~minutes for 1000 cases):
 *   MLEX_EMBEDDER=local MLEX_EMBEDDING_MIRROR=https://hf-mirror.com/ \
 *     MLEX_VECTOR_MIN_SCORE=0 \
 *     npx vitest run test/eval.semantic.bench.ts --reporter=verbose
 *
 * Thresholds are intentionally relaxed compared to the hand-crafted eval —
 * LLM-generated cases are noisier and may have borderline groundTruth choices.
 */

import { readFileSync, existsSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { afterEach, describe, expect, test } from "vitest";

import { createRuntime, type Runtime } from "../src/container.js";
import { createId } from "../src/utils/id.js";

const __dirname = dirname(fileURLToPath(import.meta.url));
const FIXTURE_PATH = join(__dirname, "fixtures/eval.semantic.cases.json");

// ─── types (mirror from eval.semantic.test.ts) ────────────────────────────────

interface SemanticCase {
  id: string;
  category: "pure-semantic" | "cross-lingual" | "paraphrase" | "noise" | "temporal" | "multi-hop";
  blocks: string[][];
  query: string;
  groundTruth: string;
  topN?: number;
  note: string;
}

interface CaseResult {
  id: string;
  category: SemanticCase["category"];
  passed: boolean;
  returnedBlocks: number;
  groundTruth: string;
  topHits: string[];
  note: string;
}

// ─── Load fixture ────────────────────────────────────────────────────────────

function loadCases(): SemanticCase[] {
  if (!existsSync(FIXTURE_PATH)) {
    console.warn(`[bench] fixture not found at ${FIXTURE_PATH}`);
    console.warn("[bench] Run: npx tsx scripts/gen-eval-cases.ts");
    return [];
  }
  const raw = readFileSync(FIXTURE_PATH, "utf8");
  return JSON.parse(raw) as SemanticCase[];
}

// ─── runner ─────────────────────────────────────────────────────────────────

async function runCase(c: SemanticCase): Promise<CaseResult> {
  const now = Date.now();
  let runtime: Runtime | undefined;
  try {
    const semanticTopK = Math.max(15, c.blocks.length + 4);
    runtime = createRuntime({
      manager: {
        enableRelationExpansion: true,
        relationDepth: 2,
        graphExpansionTopK: 4,
        finalTopK: 10,
        semanticTopK
      }
    });

    const total = c.blocks.length;
    for (let bi = 0; bi < total; bi++) {
      const offset = (total - 1 - bi) * 3000;
      for (const text of c.blocks[bi]!) {
        await runtime.memoryManager.addEvent({
          id: createId("event"),
          role: "user",
          text,
          timestamp: now - offset
        });
      }
      await runtime.memoryManager.sealCurrentBlock();
    }

    const topN = c.topN ?? 3;
    const context = await runtime.memoryManager.getContext(c.query);
    const topBlocks = context.blocks.slice(0, topN);

    const passed = topBlocks.some((b) => {
      const content = [
        b.summary ?? "",
        ...(b.rawEvents ?? []).map((e) => e.text)
      ].join(" ");
      return content.includes(c.groundTruth);
    });

    const topHits = topBlocks.slice(0, 2).map((b) =>
      [b.summary ?? "", ...(b.rawEvents ?? []).map((e) => e.text)]
        .join(" ")
        .replace(/\s+/g, " ")
        .slice(0, 72)
    );

    return {
      id: c.id,
      category: c.category,
      passed,
      returnedBlocks: context.blocks.length,
      groundTruth: c.groundTruth,
      topHits,
      note: c.note
    };
  } finally {
    await runtime?.close();
  }
}

// ─── report ─────────────────────────────────────────────────────────────────

function printReport(results: CaseResult[], embedder: string): void {
  const cats = [
    "pure-semantic", "cross-lingual", "paraphrase",
    "noise", "temporal", "multi-hop"
  ] as const;
  const lines = [`\n[bench-eval]  embedder=${embedder}  n=${results.length}`];
  for (const cat of cats) {
    const sub = results.filter(r => r.category === cat);
    if (!sub.length) continue;
    const passed = sub.filter(r => r.passed).length;
    const rate = passed / sub.length;
    const icon = rate >= 0.7 ? "✓" : rate >= 0.4 ? "~" : "✗";
    lines.push(`  ${icon} ${cat.padEnd(14)} ${passed}/${sub.length}  (${(rate * 100).toFixed(1)}%)`);
  }
  const total = results.length;
  const totalPassed = results.filter(r => r.passed).length;
  lines.push(`\n  overall: ${totalPassed}/${total}  (${((totalPassed / total) * 100).toFixed(1)}%)\n`);
  console.info(lines.join("\n"));
}

// ─── bench ───────────────────────────────────────────────────────────────────

const CASES = loadCases();

describe(
  `Semantic eval bench — ${CASES.length} generated cases`,
  () => {
    const runtimes: Runtime[] = [];
    afterEach(async () => {
      for (const rt of runtimes.splice(0)) await rt.close();
    });

    if (CASES.length === 0) {
      test("fixture missing — run scripts/gen-eval-cases.ts first", () => {
        console.info("No fixture file found. Generate cases first:");
        console.info("  npx tsx scripts/gen-eval-cases.ts");
      });
      return;
    }

    // ── Per-category sub-tests (fail-safe: each category is independent) ──────
    const cats = [
      "pure-semantic", "cross-lingual", "paraphrase",
      "noise", "temporal", "multi-hop"
    ] as const;

    for (const cat of cats) {
      const catCases = CASES.filter(c => c.category === cat);
      if (catCases.length === 0) continue;

      test(
        `category: ${cat}  (${catCases.length} cases)`,
        async () => {
          const results: CaseResult[] = [];

          // Run cases concurrently (4 at a time) for massive speedup
          const CONCURRENCY = 4;
          for (let i = 0; i < catCases.length; i += CONCURRENCY) {
            const batch = catCases.slice(i, i + CONCURRENCY);
            const batchResults = await Promise.all(batch.map(c => runCase(c)));
            results.push(...batchResults);
          }

          const embedder = process.env.MLEX_EMBEDDER ?? "hash";
          const passed = results.filter(r => r.passed).length;
          const rate = passed / results.length;

          // Print failures for debugging
          for (const r of results.filter(r => !r.passed).slice(0, 5)) {
            console.info(`  FAIL [${r.id}] groundTruth="${r.groundTruth}"`);
            for (const h of r.topHits) console.info(`    → "${h}"`);
          }

          console.info(`[${cat}] ${passed}/${results.length} (${(rate * 100).toFixed(1)}%)`);

          // Relaxed thresholds for generated cases (noisier than hand-crafted)
          const thresholds: Record<typeof cat, number> = {
            "pure-semantic": embedder === "local" ? 0.35 : 0.0,
            "cross-lingual": embedder === "local" ? 0.50 : 0.0,
            "paraphrase":    embedder === "local" ? 0.40 : 0.0,
            "noise":         embedder === "local" ? 0.40 : 0.25,  // hash struggles with needle-in-haystack
            "temporal":      0.40,
            "multi-hop":     0.35
          };

          expect(
            rate,
            `${cat} passRate ${rate.toFixed(2)} < threshold ${thresholds[cat]} (embedder=${embedder})`
          ).toBeGreaterThanOrEqual(thresholds[cat]);
        },
        { timeout: catCases.length * 8_000 + 30_000 }
      );
    }

    // ── Summary across all categories ────────────────────────────────────────
    test(
      "overall summary",
      async () => {
        const results: CaseResult[] = [];

        // Run all cases concurrently (4 at a time)
        const CONCURRENCY = 4;
        for (let i = 0; i < CASES.length; i += CONCURRENCY) {
          const batch = CASES.slice(i, i + CONCURRENCY);
          const batchResults = await Promise.all(batch.map(c => runCase(c)));
          results.push(...batchResults);
        }

        const embedder = process.env.MLEX_EMBEDDER ?? "hash";
        printReport(results, embedder);
        // No hard assertion on overall — categories handle that individually
      },
      { timeout: CASES.length * 8_000 + 60_000 }
    );
  }
);
